input.old_string:
buv_file_exists() {
  local filepath="$1"
  test -f "$filepath" || buc_die "Required file not found: $filepath"
}

input.new_string:
buv_file_exists() {
  local z_filepath="${1:-}"
  test -f "${z_filepath}" || buc_die "Required file not found: ${z_filepath}"
}

input.old_string:
buv_dir_exists() {
  local dirpath="$1"
  test -d "$dirpath" || buc_die "Required directory not found: $dirpath"
}

input.new_string:
buv_dir_exists() {
  local z_dirpath="${1:-}"
  test -d "${z_dirpath}" || buc_die "Required directory not found: ${z_dirpath}"
}

input.old_string:
buv_dir_empty() {
  local dirpath="$1"
  test -d          "$dirpath"               || buc_die "Required directory not found: $dirpath"
  test -z "$(ls -A "$dirpath" 2>/dev/null)" || buc_die "Directory must be empty: $dirpath"
}

input.new_string:
buv_dir_empty() {
  local z_dirpath="${1:-}"
  test -d          "${z_dirpath}"               || buc_die "Required directory not found: ${z_dirpath}"
  test -z "$(ls -A "${z_dirpath}" 2>/dev/null)" || buc_die "Directory must be empty: ${z_dirpath}"
}

# Setup environment
zburd_setup || { echo "ERROR: Environment setup failed" >&2; exit 1; }
zburd_show "Environment setup complete"

# Process arguments
zburd_process_args "$@" || { echo "ERROR: Argument processing failed" >&2; exit 1; }
zburd_show "Arguments processed"
